arguments.file_text:
@using System.Timers
@implements IDisposable
@inject INotificationService NotificationService

<button class="notification-badge" @onclick="OnBadgeClicked">
    🔔
    @if (_unreadCount > 0)
    {
        <span class="badge-count">@(_unreadCount > 99 ? "99+" : _unreadCount.ToString())</span>
    }
</button>

@code {
    [Parameter]
    public EventCallback OnClick { get; set; }

    private int _unreadCount;
    private Timer? _pollTimer;

    protected override async Task OnInitializedAsync()
    {
        NotificationService.OnNotificationReceived += HandleNotificationReceived;

        _unreadCount = await NotificationService.GetUnreadCountAsync();

        _pollTimer = new Timer(30_000);
        _pollTimer.Elapsed += PollUnreadCount;
        _pollTimer.Start();
    }

    private async void HandleNotificationReceived(Notification notification)
    {
        _unreadCount = await NotificationService.GetUnreadCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async void PollUnreadCount(object? sender, ElapsedEventArgs e)
    {
        _unreadCount = await NotificationService.GetUnreadCountAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnBadgeClicked()
    {
        await OnClick.InvokeAsync();
    }

    public void Dispose()
    {
        NotificationService.OnNotificationReceived -= HandleNotificationReceived;

        if (_pollTimer is not null)
        {
            _pollTimer.Elapsed -= PollUnreadCount;
            _pollTimer.Stop();
            _pollTimer.Dispose();
            _pollTimer = null;
        }
    }
}

